sys_ui_page.client_script:
addLoadEvent(function() {
	populateProcessSelect();
});

function populateProcessSelect() {
	// Mandatory styling for Type
	$j('#type').on('change', function(e) {
		if (e.target.value != '')
			$j('#process_select_type_form_group').removeClass('is-required').addClass('is-filled');
		else
			$j('#process_select_type_form_group').addClass('is-required').removeClass('is-filled');
	});

	// Mandatory styling for Type
	$j('#customer_visible').on('change', function(e) {
		if (e.target.value != '') {
			$j('#process_select_customer_visible_form_group').removeClass('is-required').addClass('is-filled');
			if (e.target.value == 'yes')
                $j('#internal_case').val('no');
            else
                $j('#internal_case').val('yes');
		} else {
			$j('#process_select_customer_visible_form_group').addClass('is-required').removeClass('is-filled');
			$j('#internal_case').val('');
		}			
	});

	var esAccountId = gel('eqix_es_account').value;
	var ou = gel('alert_account_ou').value;
	var acc = JSON.parse(esAccountId)[ou];
	var eventAccountId = gel('alert_account_id').value;
	if (ou == 'GB') {
        for (var i in acc) {
            var accounts = acc[i];	            
            if (accounts.indexOf(eventAccountId) != -1) {
                $j('#customer_visible').val("no");
                $j('#customer_visible').attr("disabled", true);
                $j('#process_select_customer_visible_form_group').removeClass('is-required').addClass('is-filled');
                $j('#internal_case').val("yes");
            }
        }
	}
	// If Account is Equinix Spain, Set Intercase as True and Read-only
	if (eventAccountId == acc) {
		$j('#customer_visible').val("no");
		$j('#customer_visible').attr("disabled", true); 
		$j('#process_select_customer_visible_form_group').removeClass('is-required').addClass('is-filled');
		$j('#internal_case').val("yes");
	}
}

function submitOk() {	
	var caseType = gel('type').value;
	var customerVisible = gel('customer_visible').value;

	// Case type is required
	if (caseType == '') {
		alert("Please select Case type");
		return false;
	}

	// Customer Visible is required
	if (customerVisible == '') {
        alert("Please select Customer visibility");
        return false;
    }

	var c = gel('cancelled');
    c.value = "false";

	g_form.modified = false;

	return true;
}

function onCancel() {
    GlideDialogWindow.get().destroy();
    return false;
}

sys_ui_page.processing_script:
if (cancelled == "false") {
    createCaseFromEventTask();
}
// Create case and associate to Event
function createCaseFromEventTask() {

    try {
        var alertIDs = alert_id;
        var caseType = type;
        var caseInternal = internal_case;
        var evntAccount = alert_account_id;
        var evntOU = alert_account_ou;
        var affectedCIs = [];

        var description = '';
        var alert = new GlideRecord('u_event_task');
        alert.addEncodedQuery('u_event_number.u_caseISEMPTY^sys_idIN' + alertIDs + '^stateIN1,2^u_autoclose_dateISEMPTY');
        alert.query();
        //https://equinixjira.atlassian.net/browse/CORE-175
        var alertIDsArray = alertIDs.split(',');
        var totalSelected = alertIDsArray.length;
        var validCount = alert.getRowCount();
        // 1. NONE valid → STOP
        if (validCount == 0) {
            gs.addErrorMessage("All Alerts selected are now closed or ready to be closed. Please review them and, if still necessary, return to the Alert list to select new active Alerts for your Event Storm.");
            response.sendRedirect('u_event_task_list.do?sysparm_query=sys_idIN' + alertIDs);
            return;
        }

        // 2. SOME valid, SOME invalid → WARNING
        if (validCount < totalSelected) {
            gs.addWarningMessage("Some of the selected Alerts are now closed or ready to be closed. The Event Storm has been created with the Events of the rest of the active Alerts.");
        }

        var firstRow = true;
        while (alert.next()) {
            description += alert.number + '\n' + '- Configuration Item: ' + alert.u_event_number.u_equipment.getDisplayValue() + '\n' + '- Short Description: ' + alert.short_description + '\n\n';

            if (affectedCIs.indexOf(alert.u_event_number.u_equipment.toString()) == -1) {
                affectedCIs.push(alert.u_event_number.u_equipment.toString());
            }
        }

        // var obj = gs.getProperty('eqix_alert_assignment');
        // var assignmentGroup = JSON.parse(obj)[evntOU];

        var grAlert = new GlideRecord("u_event_task");
        grAlert.addEncodedQuery('sys_idIN' + alertIDs);
        grAlert.query();

        if (grAlert.next()) {
            var newRecord = new GlideRecord("sn_customerservice_case");
            newRecord.initialize();
            newRecord.setValue("account", grAlert.u_event_number.u_account.toString());
            newRecord.setValue('contact_type', 'Monitoring');
            newRecord.setValue('u_type', caseType);
            newRecord.setValue('state', 10);
            newRecord.setValue('impact', 3);
            newRecord.setValue('urgency', 3);
            //newRecord.setValue('assignment_group',assignmentGroup);
            newRecord.setValue('u_operating_country', grAlert.u_operating_country);
            newRecord.setValue('u_operational_scope', grAlert.u_operational_scope);

            if (caseInternal == 'yes') {
                newRecord.setValue('u_internal_cases', true);
            } else {
                newRecord.setValue('u_internal_cases', false);
            }

            newRecord.setValue('short_description', '[' + 'Event Storm' + ']' + ' - ' + grAlert.u_event_number.u_account.getDisplayValue());
            newRecord.setValue('description', description);
            var newsys_id = newRecord.insert();

            var evntStorm = new GlideRecord('u_event_task');
            evntStorm.addEncodedQuery('sys_idIN' + alertIDs + '^stateIN1,2');
            evntStorm.query();

            while (evntStorm.next()) {
                //                 evntStorm.setValue('u_event_number.u_case',newsys_id);
                //                 evntStorm.update();
                var grEvent = new GlideRecord('u_event_management');
                grEvent.addEncodedQuery('u_caseISEMPTY^sys_idIN' + evntStorm.u_event_number + '^u_stateIN0,6');
                grEvent.query();

                if (grEvent.next()) {
                    grEvent.u_case = newsys_id;
                    grEvent.update();
                }


            }

            // Create affected CI List
            affectedCIs.forEach(function(ci) {
                var grTaskCI = new GlideRecord('task_ci');
                grTaskCI.initialize();
                grTaskCI.task = newsys_id;
                grTaskCI.ci_item = ci;
                grTaskCI.insert();
            });


            // response.sendRedirect('u_event_task.do?sys_id=' + eventTaskID);
            response.sendRedirect('sn_customerservice_case.do?sys_id=' + newsys_id);
        }

    } catch (e1) {

    }


}
